  padding: 0 20px; height: 38px; border-radius: 7px;
  text-decoration: none; white-space: nowrap;
  box-shadow: 0 4px 16px rgba(255,107,43,0.4);
  flex-shrink: 0; margin-right: 20px;
  animation: up 0.4s ease 0.4s both, glow 2.5s ease 1s infinite;
}

@keyframes up {
  from { opacity: 0; transform: translateY(6px); }
  to   { opacity: 1; transform: translateY(0); }
}
@keyframes glow {
  0%,100% { box-shadow: 0 4px 16px rgba(255,107,43,0.4); }
  50%      { box-shadow: 0 4px 26px rgba(255,107,43,0.65); }
}
</style>
</head>
